39: /**
40:  * Creates and provides access to the built-in platform and application class
41:  * loaders. It also creates the class loader that is used to locate resources
42:  * in modules defined to the boot class loader.
43:  */
44: 
45: public class ClassLoaders {
46: 
47:     private ClassLoaders() { }
48: 
49:     private static final JavaLangAccess JLA = SharedSecrets.getJavaLangAccess();
50: 
51:     // the built-in class loaders
52:     private static final BootClassLoader BOOT_LOADER;
53:     private static final PlatformClassLoader PLATFORM_LOADER;
54:     private static final AppClassLoader APP_LOADER;
55: 
56:     // Sets the ServicesCatalog for the specified loader using archived objects.
57:     private static void setArchivedServicesCatalog(ClassLoader loader) {
58:         ServicesCatalog catalog = ArchivedClassLoaders.get().servicesCatalog(loader);
59:         ServicesCatalog.putServicesCatalog(loader, catalog);
60:     }
61: 
62:     // Creates the built-in class loaders.
63:     static {
64:         ArchivedClassLoaders archivedClassLoaders = ArchivedClassLoaders.get();
65:         // -Xbootclasspath/a or -javaagent with Boot-Class-Path attribute
66:         String append = VM.getSavedProperty("jdk.boot.class.path.append");
67:         URLClassPath bootUcp = (append != null && !append.isEmpty())
68:                 ? new URLClassPath(append, true)
69:                 : null;
70:         if (archivedClassLoaders != null) {
71:             BOOT_LOADER = (BootClassLoader) archivedClassLoaders.bootLoader();
72:             BOOT_LOADER.setClassPath(bootUcp);
73:             setArchivedServicesCatalog(BOOT_LOADER);
74:             PLATFORM_LOADER = (PlatformClassLoader) archivedClassLoaders.platformLoader();
75:             setArchivedServicesCatalog(PLATFORM_LOADER);
76:         } else {
77:             BOOT_LOADER = new BootClassLoader(bootUcp);
78:             PLATFORM_LOADER = new PlatformClassLoader(BOOT_LOADER);
79:         }
80:         // A class path is required when no initial module is specified.
81:         // In this case the class path defaults to "", meaning the current
82:         // working directory.  When an initial module is specified, on the
83:         // contrary, we drop this historic interpretation of the empty
84:         // string and instead treat it as unspecified.
85:         String cp = System.getProperty("java.class.path");
86:         if (cp == null || cp.isEmpty()) {
87:             String initialModuleName = System.getProperty("jdk.module.main");
88:             cp = (initialModuleName == null) ? "" : null;
89:         }
90:         URLClassPath ucp = new URLClassPath(cp, false);
91:         if (archivedClassLoaders != null) {
92:             APP_LOADER = (AppClassLoader) archivedClassLoaders.appLoader();
93:             setArchivedServicesCatalog(APP_LOADER);
94:             APP_LOADER.setClassPath(ucp);
95:         } else {
96:             APP_LOADER = new AppClassLoader(PLATFORM_LOADER, ucp);
97:             ArchivedClassLoaders.archive();
98:         }
99:     }
100: 
101:     /**
102:      * Returns the class loader that is used to find resources in modules
103:      * defined to the boot class loader.
104:      *
105:      * @apiNote This method is not public, it should instead be used via
106:      * the BootLoader class that provides a restricted API to this class
107:      * loader.
108:      */
109:     static BuiltinClassLoader bootLoader() {
110:         return BOOT_LOADER;
111:     }
112: 
113:     /**
114:      * Returns the platform class loader.
115:      */
116:     public static ClassLoader platformClassLoader() {
117:         return PLATFORM_LOADER;
118:     }
119: 
120:     /**
121:      * Returns the application class loader.
122:      */
123:     public static ClassLoader appClassLoader() {
124:         return APP_LOADER;
125:     }
126: 
127:     /**
128:      * The class loader that is used to find resources in modules defined to
129:      * the boot class loader. It is not used for class loading.
130:      */
131:     private static class BootClassLoader extends BuiltinClassLoader {
132:         BootClassLoader(URLClassPath bcp) {
133:             super(null, null, bcp);
134:         }
135: 
136:         @Override
137:         protected Class<?> loadClassOrNull(String cn, boolean resolve) {
138:             return JLA.findBootstrapClassOrNull(cn);
139:         }
140:     };
141: 
142:     /**
143:      * The platform class loader, a unique type to make it easier to distinguish
144:      * from the application class loader.
145:      */
146:     private static class PlatformClassLoader extends BuiltinClassLoader {
147:         static {
148:             if (!ClassLoader.registerAsParallelCapable())
