402: // For a class in a named module, look it up in the jimage file using this syntax:
403: //    /<module-name>/<package-name>/<base-class>
404: //
405: // Assumptions:
406: //     1. There are no unnamed modules in the jimage file.
407: //     2. A package is in at most one module in the jimage file.
408: //
409: ClassFileStream* ClassPathImageEntry::open_stream_for_loader(JavaThread* current, const char* name, ClassLoaderData* loader_data) {
410:   jlong size;
411:   JImageLocationRef location = (*JImageFindResource)(jimage_non_null(), "", get_jimage_version_string(), name, &size);
412: 
413:   if (location == 0) {
414:     TempNewSymbol class_name = SymbolTable::new_symbol(name);
415:     TempNewSymbol pkg_name = ClassLoader::package_from_class_name(class_name);
416: 
417:     if (pkg_name != nullptr) {
418:       if (!Universe::is_module_initialized()) {
419:         location = (*JImageFindResource)(jimage_non_null(), JAVA_BASE_NAME, get_jimage_version_string(), name, &size);
420:       } else {
421:         PackageEntry* package_entry = ClassLoader::get_package_entry(pkg_name, loader_data);
422:         if (package_entry != nullptr) {
423:           ResourceMark rm(current);
424:           // Get the module name
425:           ModuleEntry* module = package_entry->module();
426:           assert(module != nullptr, "Boot classLoader package missing module");
427:           assert(module->is_named(), "Boot classLoader package is in unnamed module");
428:           const char* module_name = module->name()->as_C_string();
429:           if (module_name != nullptr) {
430:             location = (*JImageFindResource)(jimage_non_null(), module_name, get_jimage_version_string(), name, &size);
431:           }
432:         }
433:       }
434:     }
435:   }
436:   if (location != 0) {
437:     if (UsePerfData) {
438:       ClassLoader::perf_sys_classfile_bytes_read()->inc(size);
439:     }
440:     char* data = NEW_RESOURCE_ARRAY(char, size);
441:     (*JImageGetResource)(jimage_non_null(), location, data, size);
442:     // Resource allocated
443:     assert(this == (ClassPathImageEntry*)ClassLoader::get_jrt_entry(), "must be");
444:     return new ClassFileStream((u1*)data,
445:                                checked_cast<int>(size),
446:                                _name,
447:                                true); // from_boot_loader_modules_image
448:   }
449: 
450:   return nullptr;
451: }
